def _import_generated_package(package_path: str):
    parent = str(Path(package_path).parent)
    package_name = Path(package_path).name
    sys.path.insert(0, parent)
    try:
        if package_name in sys.modules:
            del sys.modules[package_name]
        return importlib.import_module(package_name)
    finally:
        if sys.path[0] == parent:
            sys.path.pop(0)


def _import_generated_runtime_module(package_path: str):
    parent = str(Path(package_path).parent)
    package_name = Path(package_path).name
    sys.path.insert(0, parent)
    try:
        sys.modules.pop(f"{package_name}.runtime", None)
        sys.modules.pop(package_name, None)
        return importlib.import_module(f"{package_name}.runtime")
    finally:
        if sys.path[0] == parent:
            sys.path.pop(0)


def _canonicalize_generated_model_source_for_raw_export_with_alarm(
    package_path: Path,
    seconds: int = 2,
) -> None:
    def _handle_alarm(signum, frame):
        raise TimeoutError("canonicalize_generated_model_source_for_raw_export timed out")

    previous_handler = signal.getsignal(signal.SIGALRM)
    signal.signal(signal.SIGALRM, _handle_alarm)
    signal.alarm(seconds)
    try:
        _canonicalize_generated_model_source_for_raw_export(package_path)
    finally:
        signal.alarm(0)
        signal.signal(signal.SIGALRM, previous_handler)


def _onnx_value_shape_signature(value_info: onnx.ValueInfoProto) -> tuple[Any, ...]:
    dims = []
    for dim in value_info.type.tensor_type.shape.dim:
        if dim.HasField("dim_value"):
            dims.append(int(dim.dim_value))
        elif dim.HasField("dim_param"):
            dims.append(str(dim.dim_param))
        else:
            dims.append("?")
    return tuple(dims)


def _onnx_model_structural_signature(model: onnx.ModelProto) -> dict[str, Any]:
    return {
        "ops": tuple(str(node.op_type) for node in model.graph.node),
        "inputs": tuple(
            (str(value_info.name), _onnx_value_shape_signature(value_info))
            for value_info in model.graph.input
        ),
        "outputs": tuple(
            (str(value_info.name), _onnx_value_shape_signature(value_info))
            for value_info in model.graph.output
        ),
        "op_counts": tuple(sorted(Counter(str(node.op_type) for node in model.graph.node).items())),
    }


def _exported_program_structural_signature(exported_program: Any) -> dict[str, Any]:
    graph_module = exported_program.module()
    nodes = []
    for node in graph_module.graph.nodes:
        if node.op != "call_function":
            continue
        meta_val = getattr(node, "meta", {}).get("val", None)
        shape = None
        if isinstance(meta_val, torch.Tensor):
            shape = tuple(str(v) for v in meta_val.shape)
        nodes.append((str(node.target), shape))
    return {
        "nodes": tuple(nodes),
        "node_counts": tuple(sorted(Counter(target for target, _ in nodes).items())),
    }


def _make_average_pool_same_exclude_pad_model() -> onnx.ModelProto:
    x = helper.make_tensor_value_info("input", TensorProto.FLOAT, [1, 1, 3, 3])
    y = helper.make_tensor_value_info("output", TensorProto.FLOAT, [1, 1, 3, 3])
    node = helper.make_node(
        "AveragePool",
        inputs=["input"],
        outputs=["output"],
        kernel_shape=[3, 3],
        strides=[1, 1],
        auto_pad="SAME_UPPER",
        count_include_pad=0,
    )
    graph = helper.make_graph([node], "average_pool_same_exclude_pad_graph", [x], [y])
    model = helper.make_model(graph, opset_imports=[helper.make_operatorsetid("", 11)])
    model.ir_version = 7
    return model


def _flatten_tensor_outputs(value: Any) -> list[torch.Tensor]:
    if isinstance(value, torch.Tensor):
        return [value]
    if isinstance(value, dict):
        tensors: list[torch.Tensor] = []
        for item in value.values():
            tensors.extend(_flatten_tensor_outputs(item))
        return tensors
    if isinstance(value, (list, tuple)):
        tensors = []
        for item in value:
            tensors.extend(_flatten_tensor_outputs(item))
        return tensors
    raise TypeError(f"Unsupported output type for comparison: {type(value)!r}")


def test_native_codegen_legacy_impl_is_not_defined_in_pytorch_exporter_module() -> None:
    exporter_source = (
        Path(__file__).resolve().parents[1] / "onnx2tf" / "tflite_builder" / "pytorch_exporter.py"
    ).read_text(encoding="utf-8")
    pipeline_source = (
        Path(__file__).resolve().parents[1]
        / "onnx2tf"
        / "tflite_builder"
        / "_pytorch_exporter_native_codegen_pipeline.py"
    ).read_text(encoding="utf-8")

    assert (
        "def _write_native_model_file_codegen_core_body_main_inner_legacy_impl("
        not in exporter_source
    )
    assert (
        "def _write_native_model_file_codegen_core_body_main_inner_legacy_impl("
        in pipeline_source
    )


def test_rewrite_channel_last_binary_bridge_chains_handles_nchw_target_shape() -> None:
    lines = [
        "in_public_layout_bridge = _torch_permute(in_t, [0, 2, 3, 1])",
        "_binary_lhs_1, _binary_rhs_1 = _align_binary_inputs(in_public_layout_bridge, self.const_tensor_623_nhwc, [1, 3, 64, 64])",
        "cv65_in = _align_tensor_to_target_shape(torch.sub(_binary_lhs_1, _binary_rhs_1), [1, 3, 64, 64])",
        "cv65_out_nhwc_cf = self.conv_block_0(cv65_in.permute(0, 3, 1, 2).contiguous())",
    ]

    rewritten = _rewrite_channel_last_binary_bridge_chains(
        lines,
        derive_local_var_name=lambda base_name: f"{base_name}_tmp",
        channel_first_constant_expr_for_buffer_attr=lambda buffer_expr, target_shape: (
            "self.const_tensor623_nhwc_ch_first1_x3_x1_x1"
            if buffer_expr == "self.const_tensor_623_nhwc" and list(target_shape) == [1, 3, 1, 1]
            else None
        ),
    )

    assert rewritten == [
        "cv65_in_cf_tmp = torch.sub(in_t, self.const_tensor623_nhwc_ch_first1_x3_x1_x1)",
        "cv65_out_nhwc_cf = self.conv_block_0(cv65_in_cf_tmp)",
    ]


def test_rewrite_binary_aligned_target_shapes_propagates_clamp_shape_to_fix_permuted_target(
    tmp_path,
) -> None:
    model_file = tmp_path / "model.py"
    model_file.write_text(
        "\n".join(
            [
                "_binary_lhs_69, _binary_rhs_69 = _align_binary_inputs_to_anchor(split_out0, clip1_out0, [1, 1, 180, 320])",
                "div_out0 = torch.div(_binary_lhs_69, _binary_rhs_69)",
                "clip2_out0 = torch.clamp(div_out0, min=0.0, max=1.0)",
                "_binary_rhs_195, _binary_lhs_195 = _align_binary_inputs_to_anchor(nsnetoutcconvconv0_cv_out_cf, clip2_out0, [1, 320, 1, 180])",
                "add4_out0 = _align_tensor_to_target_shape(torch.add(_binary_lhs_195, _binary_rhs_195), [1, 320, 1, 180])",
            ]
        )
        + "\n",
        encoding="utf-8",
    )

    _rewrite_binary_aligned_target_shapes(model_file)

    rewritten = model_file.read_text(encoding="utf-8")
    assert (
        "_align_binary_inputs_to_anchor(nsnetoutcconvconv0_cv_out_cf, clip2_out0, [1, 1, 180, 320])"
        in rewritten
    )
    assert (
        "add4_out0 = _align_tensor_to_target_shape(torch.add(_binary_lhs_195, _binary_rhs_195), [1, 1, 180, 320])"
        in rewritten
    )


