                "        super().__init__()",
                "        self.conv = torch.nn.Conv2d(in_channels, out_channels, 1, groups=groups)",
                "    def forward(self, x: torch.Tensor) -> torch.Tensor:",
                "        return self.conv(x)",
                "",
                "class Model(torch.nn.Module):",
                "    def __init__(self):",
