                "import torch.nn.functional as F",
                "",
                "class Model(torch.nn.Module):",
                "    def forward(self, branch_a_cf: torch.Tensor, branch_b_out_cf: torch.Tensor) -> torch.Tensor:",
                "        spp_average_in = _align_tensor_to_target_shape(torch.add(branch_a_cf, branch_b_out_cf), [1, 3, 5, 512])",
                "        spp_padded = F.pad(_align_tensor_to_target_shape(spp_average_in, [1, 3, 5, 512]), [0, 0, 8, 8, 8, 8], mode='constant', value=0.0)",
                "        spp_pool_out = _apply_pool2d(spp_padded, filter_height=17, filter_width=17, stride_h=8, stride_w=8, padding='VALID', target_shape=[1, 512, 1, 1], is_max_pool=False, channel_last=True)",
                "        _binary_lhs_21, _binary_rhs_21 = _align_binary_inputs_to_anchor(spp_pool_out, self.const_demo_scale3_scale3_0_AveragePool_output_nhwc_div_reciprocal_mulfused, [1, 512, 1, 512])",
