def test_export_pytorch_package_concat_torchscript_regression(tmp_path) -> None:
    model_ir = ModelIR(name="concat_torchscript_regression")
    model_ir.inputs = ["x", "y"]
    model_ir.outputs = ["z"]
    model_ir.tensors["x"] = TensorIR(
        name="x",
        dtype="FLOAT32",
        shape=[1, 2],
        shape_signature=[1, 2],
        logical_layout="UNKNOWN",
    )
    model_ir.tensors["y"] = TensorIR(
        name="y",
        dtype="FLOAT32",
        shape=[1, 2],
        shape_signature=[1, 2],
        logical_layout="UNKNOWN",
    )
    model_ir.tensors["z"] = TensorIR(
        name="z",
        dtype="FLOAT32",
        shape=[1, 4],
        shape_signature=[1, 4],
        logical_layout="UNKNOWN",
    )
    model_ir.operators = [
        OperatorIR(
            op_type="CONCATENATION",
            inputs=["x", "y"],
            outputs=["z"],
            options={"axis": 1, "fusedActivationFunction": "NONE"},
        ),
    ]

