def test_generated_batch_matmul_handles_rank_two_dense_case(tmp_path) -> None:
    package_dir = tmp_path / "batch_matmul_dense_pkg"
    package_dir.mkdir(parents=True)
    weight = torch.tensor(
        [
            [1.0, 0.0, -1.0],
            [0.5, 2.0, 0.5],
        ],
        dtype=torch.float32,
    )
    metadata = {
        "inputs": ["x"],
        "outputs": ["y"],
        "tensors": {
            "x": {
                "dtype": "FLOAT32",
                "shape": [1, 2],
                "shape_signature": [1, 2],
                "is_variable": False,
                "has_data": False,
                "logical_layout": "UNKNOWN",
            },
            "w": {
                "dtype": "FLOAT32",
                "shape": [2, 3],
                "shape_signature": [2, 3],
                "is_variable": False,
                "has_data": True,
                "logical_layout": "UNKNOWN",
            },
            "logits": {
                "dtype": "FLOAT32",
                "shape": [1, 3],
                "shape_signature": [1, 3],
                "is_variable": False,
                "has_data": False,
                "logical_layout": "UNKNOWN",
            },
            "y": {
                "dtype": "FLOAT32",
                "shape": [1, 3],
                "shape_signature": [1, 3],
                "is_variable": False,
                "has_data": False,
                "logical_layout": "UNKNOWN",
            },
        },
        "operators": [
            {
                "op_type": "BATCH_MATMUL",
                "inputs": ["x", "w"],
                "outputs": ["logits"],
                "options": {"adjX": False, "adjY": False},
            },
            {
                "op_type": "SOFTMAX",
                "inputs": ["logits"],
                "outputs": ["y"],
                "options": {"beta": 1.0},
            },
        ],
    }
    (package_dir / "metadata.json").write_text(
        json.dumps(metadata, ensure_ascii=False, indent=2),
        encoding="utf-8",
    )
    torch.save({"w": weight}, package_dir / "state_dict.pth")
    model = load_generated_model_package(
        package_dir=str(package_dir),
        eval_mode=True,
    )
    x = torch.tensor([[2.0, -1.0]], dtype=torch.float32)
    out = cast(Any, model).forward_named(x=x)["y"]
    expected = torch.softmax(torch.matmul(x, weight), dim=-1)
    assert torch.allclose(out, expected)


